import { useNavigate, useLocation } from 'react-router-dom';
import authService from '../../services/authService';

export default function AdminLayout({ children }) {
  const navigate = useNavigate();
  const location = useLocation();
  const adminEmail = authService.getEmail();
  const adminRole = authService.getRole();

  const handleLogout = () => {
    authService.logout();
    navigate('/login');
  };

  const isActive = (path) => location.pathname === path;

  return (
    <div className="min-h-screen flex flex-col bg-gray-50">
      {/* Header - Yellow Theme */}
      <header className="bg-yellow-500 text-gray-900 shadow-lg">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16">
            <div className="flex items-center space-x-4">
              <div className="w-10 h-10 bg-white rounded-lg flex items-center justify-center">
                <i className="fas fa-bolt text-yellow-600 text-xl"></i>
              </div>
              <div>
                <h1 className="text-xl font-bold">Admin Dashboard</h1>
                <p className="text-xs text-gray-800">Décennale Électricien</p>
              </div>
            </div>
            <div className="flex items-center space-x-4">
              <div className="hidden sm:block text-sm text-gray-800">
                <span className="font-medium">{adminEmail}</span>
                <span className="ml-2 px-2 py-0.5 bg-white/30 rounded text-xs">
                  {adminRole === 'ROLE_ADMIN' ? 'Admin' : 'User'}
                </span>
              </div>
              <button
                onClick={handleLogout}
                className="flex items-center space-x-2 bg-white text-yellow-600 px-4 py-2 rounded-lg hover:bg-gray-100 transition-colors"
              >
                <i className="fas fa-sign-out-alt"></i>
                <span className="hidden sm:inline">Déconnexion</span>
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {children}
      </main>

      {/* Footer - Yellow Theme */}
      <footer className="bg-yellow-500 text-gray-900 py-4">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex flex-col sm:flex-row items-center justify-between">
            <p className="text-sm font-medium">
              © 2024 Aksam Assurance. Tous droits réservés.
            </p>
            <p className="text-sm mt-2 sm:mt-0">
              Panel Admin - Gestion des leads
            </p>
          </div>
        </div>
      </footer>
    </div>
  );
}
